inline const LAM *GetLAM(const void *buf) {
  return ::flatbuffers::GetRoot<LAM>(buf);
}

inline const LAM *GetSizePrefixedLAM(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<LAM>(buf);
}

inline const char *LAMIdentifier() {
  return "$LAM";
}

inline bool LAMBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, LAMIdentifier());
}

inline bool SizePrefixedLAMBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, LAMIdentifier(), true);
}

template <bool B = false>
inline bool VerifyLAMBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifyBuffer<LAM>(LAMIdentifier());
}

template <bool B = false>
inline bool VerifySizePrefixedLAMBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifySizePrefixedBuffer<LAM>(LAMIdentifier());
}

inline void FinishLAMBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<LAM> root) {
  fbb.Finish(root, LAMIdentifier());
}

inline void FinishSizePrefixedLAMBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<LAM> root) {
  fbb.FinishSizePrefixed(root, LAMIdentifier());
}

